var (
	catalogOnce sync.Once
	catalogData map[string]map[string]string
	catalogJSON string
)

func TranslationCatalog() map[string]map[string]string {
	catalogOnce.Do(func() {
		catalogData = make(map[string]map[string]string, len(SupportedLanguages))
		for _, language := range SupportedLanguages {
			catalogData[language.Code] = make(map[string]string, len(catalogRows))
		}
		for _, row := range catalogRows {
			for i, language := range SupportedLanguages {
				if i < len(row.values) {
					catalogData[language.Code][row.key] = row.values[i]
				}
			}
		}
		bytes, err := json.Marshal(catalogData)
		if err == nil {
			catalogJSON = string(bytes)
		} else {
			catalogJSON = "{}"
		}
	})
	return catalogData
}

func CatalogJSON() string {
	TranslationCatalog()
	return catalogJSON
}

func CatalogKeys() []string {
	keys := make([]string, 0, len(catalogRows))
	for _, row := range catalogRows {
		keys = append(keys, row.key)
	}
	return keys
}
